INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Windsurf', 'windsurf', 'The agentic IDE built for AI-first development', 'Windsurf (formerly Codeium) is a full IDE built around AI coding agents. It combines deep codebase understanding with multi-file editing, terminal commands, and autonomous task completion in a familiar VS Code-like environment.', 'https://windsurf.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Autocomplete","Limited AI actions"]},{"plan":"Pro","price":"$15/mo","features":["Unlimited flows","GPT-4/Claude access"]},{"plan":"Team","price":"$30/user/mo","features":["Admin controls","SSO"]}]', 'intermediate', true, '{desktop,web}', '{"Agentic coding","Multi-file editing","Codebase-aware context","Terminal integration","Cascade flows","Supercomplete","Real-time collaboration"}', '{"Git","GitHub","GitLab","Docker","npm","pip"}', 'https://docs.windsurf.com', true, '{"Developers wanting an AI-native IDE","Teams adopting agentic workflows","Full-stack developers"}', '{"Developers who prefer minimal IDE setups"}', 'The most polished agentic IDE experience; Cascade flows feel like pair programming with a senior engineer who knows your codebase.', now()),
('Augment Code', 'augment-code', 'AI coding assistant with deep codebase understanding', 'Augment Code provides AI-powered code completion and chat with enterprise-grade codebase understanding. Indexes your entire repo for context-aware suggestions that respect your patterns and conventions.', 'https://augmentcode.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Basic autocomplete","Limited chat"]},{"plan":"Pro","price":"$30/mo","features":["Full codebase indexing","All models"]},{"plan":"Enterprise","price":"Custom","features":["SSO","Private deployment"]}]', 'intermediate', true, '{desktop}', '{"Deep codebase indexing","Context-aware completion","Multi-file chat","Code generation","Refactoring suggestions","Custom model selection"}', '{"VS Code","JetBrains","Git","GitHub"}', 'https://docs.augmentcode.com', true, '{"Enterprise developers","Large codebase teams","Developers needing codebase-aware AI"}', '{"Hobby developers on small projects"}', 'Strong codebase understanding for large repos; enterprise teams will appreciate the depth of context it maintains.', now()),
('Cline', 'cline', 'Autonomous AI coding agent for VS Code', 'Cline is an open-source VS Code extension that acts as an autonomous coding agent. It can create files, run terminal commands, use the browser, and complete multi-step tasks with human-in-the-loop approval.', 'https://cline.bot', 'free', '[{"plan":"Free","price":"$0","features":["Open-source","Bring your own API key"]}]', 'intermediate', true, '{desktop}', '{"Autonomous coding","File creation","Terminal commands","Browser use","Multi-step tasks","Human approval loop","Model agnostic","MCP support"}', '{"VS Code","Any LLM API","GitHub","Docker"}', 'https://github.com/cline/cline', true, '{"Developers wanting open-source AI agents","Power users with own API keys","Experimenters"}', '{"Non-technical users","Those wanting managed solutions"}', 'The leading open-source coding agent; bring-your-own-key model gives full control over costs and model choice.', now()),
('Bolt.new', 'bolt-new', 'Prompt to full-stack app in your browser', 'Bolt.new by StackBlitz lets you prompt, run, edit, and deploy full-stack web apps directly in the browser. Uses WebContainers to run Node.js natively, so you get a real dev environment without any local setup.', 'https://bolt.new', 'freemium', '[{"plan":"Free","price":"$0","features":["Limited tokens","Basic deploys"]},{"plan":"Pro","price":"$20/mo","features":["More tokens","Custom domains"]},{"plan":"Team","price":"$40/user/mo","features":["Collaboration","Priority"]}]', 'beginner', true, '{web}', '{"Browser-based IDE","Full-stack generation","WebContainers","Instant deploy","NPM support","Multi-file editing","Real-time preview","Netlify deploy"}', '{"Netlify","npm ecosystem","GitHub"}', 'https://docs.bolt.new', true, '{"Non-technical founders prototyping","Developers wanting quick MVPs","Learners building projects"}', '{"Production enterprise applications"}', 'Magical for prototyping — go from idea to deployed app in minutes. Not suited for complex production apps but unbeatable for speed.', now()),
('Lovable', 'lovable', 'AI full-stack engineer that builds production apps', 'Lovable (formerly GPT Engineer) is an AI tool that generates full-stack applications from natural language descriptions. Produces clean React + Supabase code with authentication, databases, and deployment built in.', 'https://lovable.dev', 'freemium', '[{"plan":"Free","price":"$0","features":["5 generations/day"]},{"plan":"Starter","price":"$20/mo","features":["More generations","Custom domains"]},{"plan":"Pro","price":"$50/mo","features":["Priority","Advanced features"]}]', 'beginner', true, '{web}', '{"Natural language to app","React + Supabase stack","Authentication built-in","Database generation","One-click deploy","Version history","Collaborative editing"}', '{"Supabase","Vercel","Netlify","GitHub"}', 'https://docs.lovable.dev', true, '{"Non-technical founders","Rapid prototypers","Solo entrepreneurs"}', '{"Complex enterprise applications","Teams with existing codebases"}', 'Impressive code quality for AI-generated apps; the Supabase integration means you get real auth and databases from the start.', now()),
('v0', 'v0-dev', 'AI-powered UI generation by Vercel', 'v0 by Vercel generates production-ready React components from text descriptions and images. Built on shadcn/ui and Tailwind CSS, it produces clean, accessible code that integrates directly into Next.js projects.', 'https://v0.dev', 'freemium', '[{"plan":"Free","price":"$0","features":["Limited generations"]},{"plan":"Premium","price":"$20/mo","features":["More generations","Priority","Private"]}]', 'intermediate', true, '{web}', '{"Text-to-UI","Image-to-code","shadcn/ui components","Tailwind CSS","Accessible output","Next.js integration","Iterative refinement","Code export"}', '{"Next.js","Vercel","shadcn/ui","Tailwind CSS","React"}', 'https://v0.dev/docs', true, '{"Frontend developers","Next.js teams","Designers prototyping UIs"}', '{"Backend developers","Non-React projects"}', 'The gold standard for AI UI generation; output is clean, accessible, and production-ready with shadcn/ui.', now()),
('Devin', 'devin', 'The first AI software engineer', 'Devin by Cognition is an autonomous AI software engineer that can plan, code, debug, and deploy entire projects. It operates in its own sandboxed environment with a shell, code editor, and browser.', 'https://devin.ai', 'paid', '[{"plan":"Team","price":"$500/mo","features":["Autonomous engineering","Slack integration","Full environment"]}]', 'advanced', true, '{web}', '{"Autonomous coding","Planning and execution","Shell access","Browser use","Debugging","Deployment","Slack integration","Long-running tasks"}', '{"GitHub","Slack","Linear","Jira"}', 'https://docs.devin.ai', true, '{"Engineering teams with backlogs","Companies automating routine dev work","Teams wanting async AI engineers"}', '{"Solo developers on budget","Simple scripting tasks"}', 'Genuinely autonomous for well-scoped tasks; the $500/mo price point means it needs to replace meaningful engineering hours to justify cost.', now()),
('Claude Code', 'claude-code', 'Anthropic''s agentic coding tool in the terminal', 'Claude Code is Anthropic''s official CLI tool that brings Claude directly into your terminal. It understands your entire codebase, can edit files, run commands, and complete complex multi-step engineering tasks with human oversight.', 'https://claude.ai/code', 'paid', '[{"plan":"Max","price":"$100/mo","features":["Included with Claude Max plan"]},{"plan":"API","price":"Usage-based","features":["Pay per token"]}]', 'intermediate', true, '{cli,desktop,web}', '{"Terminal-native","Full codebase understanding","Multi-file editing","Command execution","Git integration","Human-in-the-loop","IDE extensions","MCP support"}', '{"VS Code","JetBrains","Git","GitHub","Terminal"}', 'https://docs.anthropic.com/en/docs/claude-code', true, '{"Professional developers","Terminal-first workflows","Teams wanting agentic coding"}', '{"Non-technical users","GUI-only preferences"}', 'The most capable terminal-based coding agent; deep codebase understanding and careful human-in-the-loop design make it trustworthy for production work.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('n8n', 'n8n', 'Open-source workflow automation with AI capabilities', 'n8n is an open-source workflow automation platform that connects apps and services with AI agents. Build complex automations visually, add AI nodes for LLM calls, and self-host for full data control.', 'https://n8n.io', 'freemium', '[{"plan":"Community","price":"$0","features":["Self-host","Unlimited workflows"]},{"plan":"Starter","price":"$20/mo","features":["Cloud hosted","5 workflows"]},{"plan":"Pro","price":"$50/mo","features":["Unlimited workflows","Sharing"]}]', 'intermediate', true, '{web,cli}', '{"Visual workflow builder","400+ integrations","AI agent nodes","Code nodes","Webhooks","Scheduling","Error handling","Self-hostable","Credential management"}', '{"Slack","Gmail","Notion","Airtable","PostgreSQL","OpenAI","Anthropic","Google Sheets"}', 'https://docs.n8n.io', true, '{"Developers building AI automations","Self-hosting advocates","Teams replacing Zapier"}', '{"Non-technical users wanting simple automations"}', 'The best open-source alternative to Zapier/Make with native AI agent capabilities; self-hosting means your data stays yours.', now()),
('Make', 'make', 'Visual platform for building complex automations', 'Make (formerly Integromat) is a visual automation platform with thousands of app integrations. Its visual canvas makes complex multi-step workflows intuitive, with built-in AI and data transformation tools.', 'https://make.com', 'freemium', '[{"plan":"Free","price":"$0","features":["1,000 ops/mo","2 scenarios"]},{"plan":"Core","price":"$9/mo","features":["10,000 ops/mo","Unlimited scenarios"]},{"plan":"Pro","price":"$16/mo","features":["Custom functions","Priority"]}]', 'beginner', true, '{web,api}', '{"Visual canvas","2000+ app integrations","AI modules","Data transformation","Scheduling","Error handling","Webhooks","Custom functions","API connections"}', '{"Google Workspace","Slack","Shopify","HubSpot","Salesforce","OpenAI","Notion","Airtable"}', 'https://www.make.com/en/help', true, '{"Small businesses automating workflows","Marketers connecting tools","Non-technical automation builders"}', '{"Enterprise needing on-premise solutions"}', 'More powerful than Zapier for complex logic with a better visual interface; the free tier is generous enough to validate use cases.', now()),
('Activepieces', 'activepieces', 'Open-source AI-first automation platform', 'Activepieces is an open-source automation platform designed for AI workflows. Build automations with a visual editor, connect to 200+ apps, and add AI steps powered by any LLM provider. Self-host or use cloud.', 'https://activepieces.com', 'freemium', '[{"plan":"Community","price":"$0","features":["Self-host","Unlimited flows"]},{"plan":"Pro","price":"$10/mo","features":["Cloud hosted","Priority support"]},{"plan":"Enterprise","price":"Custom","features":["SSO","Audit logs"]}]', 'intermediate', true, '{web,cli}', '{"Open-source","AI-first design","200+ integrations","Visual builder","Pieces (custom code)","Multi-tenant","Webhooks","Scheduling"}', '{"OpenAI","Anthropic","Google Sheets","Slack","Discord","GitHub","Notion"}', 'https://activepieces.com/docs', true, '{"Teams wanting open-source automation","AI workflow builders","Startups on budget"}', '{"Enterprise needing massive scale immediately"}', 'Fast-growing open-source automation platform with genuine AI-first design; a strong n8n alternative with cleaner UI.', now()),
('Bardeen', 'bardeen', 'AI automation that runs in your browser', 'Bardeen is a browser-based automation tool that scrapes web data, connects apps, and automates repetitive tasks using AI. It runs directly in Chrome, scraping and interacting with web pages without code.', 'https://bardeen.ai', 'freemium', '[{"plan":"Free","price":"$0","features":["Non-premium automations"]},{"plan":"Pro","price":"$10/mo","features":["Premium integrations","AI credits"]}]', 'beginner', false, '{web}', '{"Browser automation","Web scraping","AI actions","No-code builder","Chrome extension","App connections","Templates","Scheduling"}', '{"LinkedIn","Google Sheets","Notion","Slack","HubSpot","Salesforce","Airtable"}', 'https://bardeen.ai/playbooks', true, '{"Sales teams scraping leads","Recruiters","Anyone automating browser tasks"}', '{"Backend automation needs"}', 'Brilliant for browser-based automations that other tools can''t do; LinkedIn scraping and web data extraction are standout features.', now()),
('Lindy', 'lindy', 'Build AI agents that work for you 24/7', 'Lindy lets you create custom AI agents (called Lindies) that handle tasks like email triage, meeting scheduling, CRM updates, and customer support. Agents learn from your behavior and connect to your tools.', 'https://lindy.ai', 'freemium', '[{"plan":"Free","price":"$0","features":["Limited agents","400 credits"]},{"plan":"Pro","price":"$50/mo","features":["Unlimited agents","Priority"]},{"plan":"Business","price":"$200/mo","features":["Team features","Custom models"]}]', 'beginner', true, '{web}', '{"Custom AI agents","Email triage","Meeting scheduling","CRM automation","Multi-agent orchestration","Learning from behavior","Slack integration","Trigger-based"}', '{"Gmail","Google Calendar","Salesforce","HubSpot","Slack","Notion","Linear"}', 'https://docs.lindy.ai', true, '{"Executives automating admin work","Sales teams managing pipelines","Anyone drowning in email"}', '{"Developers wanting full control over AI logic"}', 'The most approachable AI agent builder; email triage alone can save hours per week for busy professionals.', now()),
('Bland AI', 'bland-ai', 'AI phone agents that sound human', 'Bland AI provides AI-powered phone agents that can make and receive calls with human-like voice quality. Build custom phone workflows for sales, support, scheduling, and surveys with natural conversation handling.', 'https://bland.ai', 'paid', '[{"plan":"Enterprise","price":"$0.09/min","features":["Custom voices","Call transfers","Webhooks","Analytics"]}]', 'intermediate', true, '{web,api}', '{"AI phone calls","Human-like voices","Custom workflows","Call transfers","Webhook triggers","Conversation scripts","Real-time analytics","Multi-language"}', '{"Salesforce","HubSpot","Zapier","Make","Twilio","Calendly"}', 'https://docs.bland.ai', true, '{"Sales teams making outbound calls","Support centers","Appointment scheduling businesses"}', '{"Personal use","Low call volume needs"}', 'Impressively natural phone conversations; the per-minute pricing makes it accessible for testing before scaling.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Julius AI', 'julius-ai', 'Chat with your data using AI', 'Julius AI lets you upload spreadsheets, CSVs, and databases, then ask questions in natural language. It generates visualizations, performs statistical analysis, and creates reports — all through conversation.', 'https://julius.ai', 'freemium', '[{"plan":"Free","price":"$0","features":["Limited messages","Basic charts"]},{"plan":"Pro","price":"$20/mo","features":["Unlimited messages","Advanced analysis"]},{"plan":"Team","price":"$40/user/mo","features":["Shared workspace","Priority"]}]', 'beginner', false, '{web}', '{"Natural language data analysis","Auto visualization","Statistical analysis","CSV/Excel upload","SQL database connection","Report generation","Python code execution"}', '{"Google Sheets","PostgreSQL","MySQL","Snowflake","Excel"}', 'https://julius.ai/docs', true, '{"Business analysts","Non-technical data exploration","Quick data insights"}', '{"Data engineers needing production pipelines"}', 'The fastest way to explore data if you''re not a SQL expert; chart generation is particularly impressive.', now()),
('Hex', 'hex', 'Collaborative data workspace with AI', 'Hex combines SQL, Python, and no-code tools in a collaborative notebook with AI assistance. Build data apps, dashboards, and analyses that anyone on your team can understand and interact with.', 'https://hex.tech', 'freemium', '[{"plan":"Free","price":"$0","features":["Single user","Basic features"]},{"plan":"Pro","price":"$28/user/mo","features":["Collaboration","Scheduling"]},{"plan":"Team","price":"$42/user/mo","features":["Version control","SSO"]}]', 'intermediate', true, '{web}', '{"SQL + Python notebooks","AI assistant","Interactive dashboards","Data apps","Version control","Scheduling","Parameterized queries","Collaboration"}', '{"Snowflake","BigQuery","PostgreSQL","Redshift","dbt","Fivetran","GitHub"}', 'https://learn.hex.tech', true, '{"Data teams building analyses","Analysts sharing insights","Teams wanting interactive reports"}', '{"Simple spreadsheet tasks","Non-data teams"}', 'The best modern data notebook; AI assistant genuinely understands your data context and writes correct SQL.', now()),
('Databricks AI', 'databricks-ai', 'Unified analytics platform with AI and ML', 'Databricks provides a lakehouse platform combining data engineering, analytics, and AI/ML. Features include Mosaic AI for model training, Delta Lake for reliable storage, and Unity Catalog for governance.', 'https://databricks.com', 'enterprise', '[{"plan":"Standard","price":"Usage-based","features":["Interactive workloads","SQL analytics"]},{"plan":"Premium","price":"Usage-based","features":["ML runtime","Unity Catalog"]},{"plan":"Enterprise","price":"Custom","features":["Full governance","Support"]}]', 'advanced', true, '{web,api,cli}', '{"Lakehouse architecture","Mosaic AI","Delta Lake","Unity Catalog","MLflow","Spark","AutoML","Model serving","Feature store","SQL warehouses"}', '{"AWS","Azure","GCP","Snowflake","dbt","Fivetran","Tableau","Power BI"}', 'https://docs.databricks.com', true, '{"Enterprise data teams","ML engineering organizations","Large-scale data platforms"}', '{"Small teams with simple data needs"}', 'The most comprehensive data + AI platform; overkill for small teams but unmatched for enterprise-scale data operations.', now()),
('Weights & Biases', 'wandb', 'ML experiment tracking and model management', 'Weights & Biases (W&B) provides experiment tracking, model versioning, dataset management, and collaborative ML dashboards. The go-to platform for ML teams to log, compare, and reproduce experiments.', 'https://wandb.ai', 'freemium', '[{"plan":"Free","price":"$0","features":["Personal projects","100GB storage"]},{"plan":"Team","price":"$50/user/mo","features":["Collaboration","Priority support"]},{"plan":"Enterprise","price":"Custom","features":["SSO","Audit logs","On-prem"]}]', 'advanced', true, '{web,api,cli}', '{"Experiment tracking","Model versioning","Dataset management","Hyperparameter sweeps","Collaborative dashboards","Artifacts","Reports","Prompts playground"}', '{"PyTorch","TensorFlow","Hugging Face","Keras","scikit-learn","XGBoost","Lightning"}', 'https://docs.wandb.ai', true, '{"ML researchers","Data science teams","AI startups tracking experiments"}', '{"Non-ML data analysts"}', 'The undisputed leader in ML experiment tracking; every serious ML team uses it or should consider it.', now()),
('LabelStudio', 'label-studio', 'Open-source data labeling platform', 'Label Studio is an open-source platform for labeling data across text, images, audio, video, and time series. Features AI-assisted labeling, quality control workflows, and integration with ML pipelines.', 'https://labelstud.io', 'freemium', '[{"plan":"Community","price":"$0","features":["Open-source","Unlimited projects"]},{"plan":"Enterprise","price":"Custom","features":["Analytics","SSO","RBAC","Workflows"]}]', 'intermediate', true, '{web,api,cli}', '{"Multi-modal labeling","AI-assisted labeling","Quality control","Template library","Custom interfaces","ML backend integration","Active learning","Team management"}', '{"Hugging Face","AWS SageMaker","Azure ML","GCP Vertex","Python ML frameworks"}', 'https://labelstud.io/guide', true, '{"ML teams building training datasets","Research groups","Annotation team managers"}', '{"Teams with pre-labeled data"}', 'Best open-source labeling tool by far; the AI-assisted labeling genuinely speeds up annotation workflows.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Intercom Fin', 'intercom-fin', 'AI-first customer service agent', 'Fin is Intercom''s AI customer service agent that resolves up to 50% of support conversations instantly. It learns from your help center, previous conversations, and custom data to provide accurate, personalized responses.', 'https://intercom.com/fin', 'paid', '[{"plan":"Essential","price":"$29/seat/mo","features":["Fin AI Agent","Inbox"]},{"plan":"Advanced","price":"$85/seat/mo","features":["Workflows","Reporting"]},{"plan":"Expert","price":"$132/seat/mo","features":["Custom objects","SSO"]}]', 'beginner', true, '{web,mobile}', '{"AI resolution","Help center learning","Conversation handoff","Multi-language","Custom answers","Reporting","Workflow automation","Messenger customization"}', '{"Salesforce","HubSpot","Slack","Stripe","Shopify","Zendesk","Segment"}', 'https://developers.intercom.com', true, '{"SaaS companies","E-commerce support","Teams with high ticket volume"}', '{"Teams with very niche/technical support needs"}', 'The most polished AI support agent on the market; 50% auto-resolution is achievable if your help center is solid.', now()),
('Zendesk AI', 'zendesk-ai', 'AI-powered customer service platform', 'Zendesk AI infuses artificial intelligence throughout the customer service workflow — from intelligent triage and agent assistance to automated resolutions. Built on billions of real customer interactions.', 'https://zendesk.com/ai', 'paid', '[{"plan":"Suite Team","price":"$55/agent/mo","features":["Basic AI","Ticketing"]},{"plan":"Suite Growth","price":"$89/agent/mo","features":["AI agents","Self-service"]},{"plan":"Suite Professional","price":"$115/agent/mo","features":["Advanced AI","Analytics"]}]', 'beginner', true, '{web,mobile,api}', '{"AI triage","Agent assistance","Automated resolutions","Intent detection","Sentiment analysis","Knowledge base AI","Macros suggestions","CSAT prediction"}', '{"Salesforce","Shopify","Slack","Jira","Mailchimp","Segment","AWS"}', 'https://developer.zendesk.com', true, '{"Enterprise support teams","Multi-channel support operations","Regulated industries"}', '{"Small startups wanting simple solutions"}', 'Enterprise-grade AI support with the broadest feature set; the training data from billions of conversations shows in accuracy.', now()),
('Drift', 'drift', 'AI-powered conversational marketing and sales', 'Drift (now part of Salesloft) provides AI chatbots for website conversion. Engage visitors in real-time conversations, qualify leads, book meetings, and route to sales reps — all powered by AI.', 'https://drift.com', 'paid', '[{"plan":"Premium","price":"Custom","features":["AI chatbot","Live chat","Meetings"]},{"plan":"Advanced","price":"Custom","features":["A/B testing","Custom bots"]},{"plan":"Enterprise","price":"Custom","features":["Workspaces","Custom RBAC"]}]', 'beginner', true, '{web,api}', '{"AI chatbot","Lead qualification","Meeting booking","Visitor intelligence","Playbooks","A/B testing","Account-based targeting","Revenue reporting"}', '{"Salesforce","HubSpot","Marketo","Outreach","6sense","Clearbit","Slack"}', 'https://developers.drift.com', true, '{"B2B SaaS companies","Sales-driven organizations","Marketing teams wanting chat conversion"}', '{"B2C companies","Content-only websites"}', 'The pioneer of conversational marketing; AI qualification genuinely increases pipeline by catching high-intent visitors.', now()),
('Voiceflow', 'voiceflow', 'Design and deploy AI agents across channels', 'Voiceflow is a platform for designing, prototyping, and deploying conversational AI agents. Build chatbots and voice assistants with a visual canvas, integrate with knowledge bases, and launch on any channel.', 'https://voiceflow.com', 'freemium', '[{"plan":"Sandbox","price":"$0","features":["1 agent","Basic features"]},{"plan":"Pro","price":"$50/mo","features":["Unlimited agents","API access"]},{"plan":"Team","price":"$625/mo","features":["Collaboration","Analytics"]}]', 'intermediate', true, '{web,api}', '{"Visual conversation designer","Knowledge base integration","Multi-channel deploy","API integration","NLU training","Analytics","A/B testing","Custom functions"}', '{"Twilio","Zendesk","Intercom","Slack","WhatsApp","Web embed","REST APIs"}', 'https://docs.voiceflow.com', true, '{"Product teams building chatbots","Customer experience designers","AI agent builders"}', '{"Simple FAQ bots","Non-conversational AI needs"}', 'Best visual conversation designer for complex AI agents; the canvas makes it easy to handle edge cases that other tools miss.', now()),
('Ada', 'ada-ai', 'AI customer service automation platform', 'Ada provides an AI-powered platform that automates customer service across messaging, email, phone, and social channels. Uses your existing knowledge base to resolve inquiries without human agents.', 'https://ada.cx', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Multi-channel AI","Knowledge integration","Analytics","SSO"]}]', 'beginner', true, '{web,api}', '{"Multi-channel support","Knowledge base AI","Handoff to agents","Analytics","Multi-language","Custom actions","Proactive messaging","CSAT tracking"}', '{"Salesforce","Zendesk","Shopify","Twilio","Contentful","Segment"}', 'https://docs.ada.cx', true, '{"Large enterprises","Multi-channel support teams","Companies with high ticket volume"}', '{"Small teams with low volume"}', 'Enterprise-focused automated support with strong multi-channel coverage; resolution rates improve dramatically with good knowledge bases.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Flux', 'flux-ai', 'Open-source image generation by Black Forest Labs', 'Flux is a family of state-of-the-art open-source image generation models by Black Forest Labs (from the original Stable Diffusion team). Known for exceptional prompt adherence, text rendering, and photorealistic output.', 'https://blackforestlabs.ai', 'freemium', '[{"plan":"Open","price":"$0","features":["Open-weight models","Self-host"]},{"plan":"API","price":"Usage-based","features":["Hosted inference","Pro models"]}]', 'intermediate', true, '{web,api}', '{"State-of-art image generation","Text rendering","Open-source models","Prompt adherence","Photorealism","Multiple model sizes","LoRA support","ControlNet compatible"}', '{"Replicate","Together AI","fal.ai","ComfyUI","Automatic1111"}', 'https://blackforestlabs.ai/flux-1/', true, '{"AI artists","Developers building image features","Open-source model enthusiasts"}', '{"Non-technical users wanting easy interface"}', 'The best open-source image model available; text rendering in images actually works, which was a major weakness of prior models.', now()),
('Kling AI', 'kling-ai', 'Professional AI video generation', 'Kling AI by Kuaishou generates high-quality videos from text prompts and images. Known for strong motion quality, long video generation (up to 2 minutes), and cinematic camera controls.', 'https://klingai.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Limited generations"]},{"plan":"Standard","price":"$8/mo","features":["More generations","Priority"]},{"plan":"Pro","price":"$28/mo","features":["High quality","2 min videos"]}]', 'beginner', true, '{web,api}', '{"Text-to-video","Image-to-video","Camera controls","Up to 2 min videos","Motion brush","Lip sync","Professional mode","4K output"}', '{"API access","ComfyUI"}', 'https://docs.klingai.com', true, '{"Content creators","Social media marketers","Video production teams"}', '{"Real-time video needs"}', 'One of the strongest video generation models; 2-minute generation length and camera controls set it apart from competitors.', now()),
('ElevenLabs', 'elevenlabs', 'The most realistic AI voice platform', 'ElevenLabs provides the most natural-sounding AI text-to-speech and voice cloning. Generate speech in 29 languages, clone voices from samples, and build voice-enabled applications with their API.', 'https://elevenlabs.io', 'freemium', '[{"plan":"Free","price":"$0","features":["10,000 chars/mo","3 custom voices"]},{"plan":"Starter","price":"$5/mo","features":["30,000 chars/mo","10 voices"]},{"plan":"Creator","price":"$22/mo","features":["100,000 chars/mo","30 voices"]},{"plan":"Pro","price":"$99/mo","features":["500,000 chars/mo","160 voices"]}]', 'beginner', true, '{web,api}', '{"Text-to-speech","Voice cloning","29 languages","Voice design","Projects editor","Dubbing","Sound effects","Conversational AI","Voice library"}', '{"API integration","Unity","Unreal Engine","Python SDK","JavaScript SDK"}', 'https://elevenlabs.io/docs', true, '{"Content creators","App developers adding voice","Audiobook producers","Dubbing studios"}', '{"Live real-time voice needs at scale"}', 'The benchmark for AI voice quality; voice cloning is eerily accurate and the multilingual support is production-ready.', now()),
('Suno', 'suno', 'Make music with AI — full songs from text', 'Suno generates complete songs with vocals, instruments, and production from text descriptions. Describe a genre, mood, and topic, and Suno creates a full 3-4 minute song with lyrics.', 'https://suno.com', 'freemium', '[{"plan":"Free","price":"$0","features":["10 songs/day","Non-commercial"]},{"plan":"Pro","price":"$10/mo","features":["500 songs/mo","Commercial use"]},{"plan":"Premier","price":"$30/mo","features":["2000 songs/mo","Priority"]}]', 'beginner', false, '{web}', '{"Text-to-song","Vocal generation","Multiple genres","Custom lyrics","Instrumental mode","Song extension","Remix","Download"}', '{}', 'https://suno.com/blog', true, '{"Content creators needing music","Social media producers","Podcasters","Hobbyist musicians"}', '{"Professional music producers","Commercial music licensing"}', 'Genuinely impressive song generation with coherent lyrics and production; the free tier is generous enough to explore.', now()),
('Udio', 'udio', 'AI music creation with studio-quality output', 'Udio generates high-fidelity music from text descriptions with remarkable genre accuracy and production quality. Create up to 15-minute tracks with vocals, explore style variations, and iterate on sections.', 'https://udio.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Limited generations"]},{"plan":"Standard","price":"$10/mo","features":["1200 songs/mo","Commercial use"]},{"plan":"Pro","price":"$30/mo","features":["4800 songs/mo","Priority"]}]', 'beginner', false, '{web}', '{"Text-to-music","Studio quality","Long-form tracks","Style control","Vocal generation","Genre accuracy","Section editing","Audio extensions"}', '{}', 'https://udio.com/blog', true, '{"Musicians exploring AI","Filmmakers needing soundtracks","Content creators"}', '{"Professional recording studios"}', 'Arguably the highest audio fidelity in AI music; genre accuracy and production quality rival Suno with slightly more musical depth.', now()),
('Perplexity', 'perplexity', 'AI-powered search engine with cited answers', 'Perplexity is an AI search engine that provides direct answers with inline citations. It searches the web in real-time, synthesizes information from multiple sources, and presents clear, sourced responses.', 'https://perplexity.ai', 'freemium', '[{"plan":"Free","price":"$0","features":["Unlimited quick searches","5 Pro searches/day"]},{"plan":"Pro","price":"$20/mo","features":["300+ Pro searches/day","File upload","API access"]}]', 'beginner', true, '{web,mobile,api}', '{"AI search","Cited answers","Real-time web search","Focus modes","File analysis","Collections","Pro Search","Multi-model access","API"}', '{"Chrome extension","iOS","Android","Arc browser"}', 'https://docs.perplexity.ai', true, '{"Researchers needing sourced answers","Professionals fact-checking","Anyone replacing Google for questions"}', '{"Creative writing","Tasks not requiring factual accuracy"}', 'The most useful AI search engine; inline citations build trust that ChatGPT lacks, and Pro Search handles complex research surprisingly well.', now()),
('NotebookLM', 'notebooklm', 'Google''s AI research assistant', 'NotebookLM by Google is an AI-powered research assistant that works with your uploaded documents. It generates summaries, answers questions grounded in your sources, and creates audio overviews — all cited back to your materials.', 'https://notebooklm.google.com', 'free', '[{"plan":"Free","price":"$0","features":["Up to 50 sources","All features"]}]', 'beginner', false, '{web}', '{"Source-grounded AI","Audio Overview","Document Q&A","Inline citations","Multi-source synthesis","Study guides","Briefing docs","FAQ generation"}', '{"Google Drive","PDF","Google Docs","Websites","YouTube transcripts"}', 'https://support.google.com/notebooklm', true, '{"Students studying documents","Researchers analyzing papers","Professionals reviewing reports"}', '{"Real-time web search needs","Code-related tasks"}', 'The best free research assistant; Audio Overview feature is genuinely magical for turning papers into podcast-style summaries.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Granola', 'granola', 'AI notepad for meetings that actually works', 'Granola is an AI meeting notepad that enhances your own notes with AI. It listens to your meetings, then enriches your rough notes with full context, action items, and summaries — without being a visible bot in the call.', 'https://granola.ai', 'freemium', '[{"plan":"Free","price":"$0","features":["25 meetings/mo","Basic AI"]},{"plan":"Pro","price":"$10/mo","features":["Unlimited meetings","Templates","CRM sync"]}]', 'beginner', false, '{desktop}', '{"Meeting transcription","Note enhancement","No meeting bot","Action items","Custom templates","CRM sync","Multi-language","Privacy-first"}', '{"Google Meet","Zoom","Microsoft Teams","Salesforce","HubSpot","Notion"}', 'https://granola.ai/help', true, '{"Professionals in frequent meetings","Sales teams","Managers tracking action items"}', '{"Podcast/content transcription"}', 'The best meeting note tool because it doesn''t announce itself as a bot; the note-enhancement approach respects meeting dynamics.', now()),
('Raycast', 'raycast', 'Supercharged productivity launcher with AI built in', 'Raycast is a Mac productivity launcher that replaces Spotlight with AI-powered features. Quick access to AI chat, snippets, clipboard history, window management, and hundreds of extensions — all from a keyboard shortcut.', 'https://raycast.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Core features","Extensions"]},{"plan":"Pro","price":"$8/mo","features":["AI Chat","Cloud sync","Custom themes"]},{"plan":"Team","price":"$12/user/mo","features":["Shared snippets","AI for teams"]}]', 'intermediate', false, '{desktop}', '{"AI chat in launcher","Clipboard history","Snippets","Window management","Extensions store","Calculator","File search","Script commands","Quicklinks"}', '{"GitHub","Jira","Linear","Notion","Slack","VS Code","1Password","Figma"}', 'https://developers.raycast.com', true, '{"Mac power users","Developers","Productivity enthusiasts"}', '{"Windows/Linux users","Mouse-first workflows"}', 'The best Mac productivity tool, period. AI chat accessible from anywhere via hotkey is a game-changer for daily workflows.', now()),
('Tldraw', 'tldraw', 'AI-powered collaborative whiteboard and drawing tool', 'Tldraw is an open-source collaborative whiteboard with AI features. Draw shapes, diagrams, and UI mockups, then use AI to convert drawings to code, generate images, or refine designs. Fully embeddable.', 'https://tldraw.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Core whiteboard","Collaboration"]},{"plan":"Plus","price":"$8/mo","features":["AI features","Shared projects"]}]', 'beginner', true, '{web}', '{"Collaborative whiteboard","Drawing to code","AI shape generation","Real-time collaboration","Infinite canvas","Shape library","Export options","Open-source core"}', '{"React","Next.js","GitHub"}', 'https://tldraw.dev', true, '{"Designers prototyping","Developers whiteboarding","Remote teams collaborating"}', '{"Detailed design work (use Figma)"}', 'Delightful whiteboard with the smartest AI-to-code feature; open-source core means you can embed it anywhere.', now()),
('Taskade', 'taskade-ai', 'AI workspace for tasks, notes, and mind maps', 'Taskade is an AI-powered workspace that combines task management, notes, mind maps, and real-time collaboration. AI agents can generate projects, automate workflows, and chat with your workspace data.', 'https://taskade.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Limited projects","Basic AI"]},{"plan":"Pro","price":"$8/mo","features":["Unlimited projects","AI agents"]},{"plan":"Team","price":"$16/user/mo","features":["Admin tools","Priority"]}]', 'beginner', true, '{web,mobile,desktop}', '{"AI task generation","Mind maps","Real-time collaboration","AI agents","Templates","Calendar view","Video chat","Custom workflows","API"}', '{"Google Drive","Dropbox","Zapier","Slack","GitHub"}', 'https://taskade.com/blog', true, '{"Small teams wanting all-in-one workspace","Project managers","Remote teams"}', '{"Enterprise project management","Developer-centric workflows"}', 'Impressive all-in-one workspace with genuinely useful AI; the mind map and task generation features are standouts.', now())
